// IncidentTimeline — interactive incident list + per-incident event timeline
import React, { useCallback, useEffect, useRef, useState } from 'react';

const API_BASE = 'http://localhost:8000';

const STATUS_COLOR = {
    open: '#ff5252',
    investigating: '#ffc107',
    contained: '#29b6f6',
    resolved: '#4caf50',
    closed: '#9e9e9e',
};

const SEVERITY_COLOR = {
    critical: '#ff1744',
    high: '#ff5722',
    medium: '#ffc107',
    low: '#4caf50',
    info: '#29b6f6',
};

function StatusDot({ status }) {
    const s = (status || 'open').toLowerCase();
    return (
        <span
            style={{
                display: 'inline-block',
                width: 8,
                height: 8,
                borderRadius: '50%',
                background: STATUS_COLOR[s] || '#9e9e9e',
                marginRight: 6,
                flexShrink: 0,
                boxShadow: `0 0 5px ${STATUS_COLOR[s] || '#9e9e9e'}`,
            }}
        />
    );
}

function Timeline({ events, loading }) {
    if (loading) {
        return (
            <div style={{ color: '#29b6f6', fontSize: '0.78rem', padding: '8px 0' }}>
                Loading timeline…
            </div>
        );
    }
    if (!events || events.length === 0) {
        return (
            <div style={{ color: '#546e7a', fontSize: '0.78rem', padding: '8px 0' }}>
                No timeline events.
            </div>
        );
    }

    return (
        <div style={{ position: 'relative', paddingLeft: 18, marginTop: 8 }}>
            {/* Vertical rail */}
            <div
                style={{
                    position: 'absolute',
                    left: 7,
                    top: 6,
                    bottom: 6,
                    width: 2,
                    background: 'linear-gradient(to bottom, #29b6f6, #0d2b3e)',
                    borderRadius: 2,
                }}
            />
            {events.map((ev, idx) => {
                const ts = ev.timestamp
                    ? new Date(ev.timestamp).toLocaleString()
                    : '—';
                return (
                    <div
                        key={ev.id ?? idx}
                        style={{
                            position: 'relative',
                            marginBottom: 14,
                            paddingLeft: 16,
                        }}
                    >
                        {/* Dot on rail */}
                        <div
                            style={{
                                position: 'absolute',
                                left: -6,
                                top: 4,
                                width: 10,
                                height: 10,
                                borderRadius: '50%',
                                background: '#29b6f6',
                                border: '2px solid #0a0d10',
                                boxShadow: '0 0 6px #29b6f6',
                            }}
                        />
                        <div
                            style={{
                                fontSize: '0.72rem',
                                color: '#546e7a',
                                marginBottom: 2,
                            }}
                        >
                            {ts}
                            {ev.actor && (
                                <span style={{ marginLeft: 8, color: '#78909c' }}>
                                    — {ev.actor}
                                </span>
                            )}
                        </div>
                        <div style={{ fontSize: '0.82rem', color: '#cfe8ff', fontWeight: 500 }}>
                            {ev.event_type || ev.type || 'Event'}
                        </div>
                        {ev.description && (
                            <div style={{ fontSize: '0.74rem', color: '#8ab4c7', marginTop: 2 }}>
                                {ev.description}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

export default function IncidentTimeline() {
    const [incidents, setIncidents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [expandedId, setExpandedId] = useState(null);
    const [timelineData, setTimelineData] = useState({});
    const [timelineLoading, setTimelineLoading] = useState({});
    const timerRef = useRef(null);

    const setIncidentStatus = useCallback((incidentId, nextStatus) => {
        fetch(`${API_BASE}/incidents/${incidentId}/status?status=${encodeURIComponent(nextStatus)}`, {
            method: 'PATCH',
        })
            .then((r) => {
                if (!r.ok) throw new Error(`HTTP ${r.status}`);
                return r.json();
            })
            .then(() => {
                setIncidents((prev) => prev.map((inc) => (
                    inc.id === incidentId ? { ...inc, status: nextStatus } : inc
                )));
            })
            .catch(() => {
                // no-op: periodic refresh reconciles state
            });
    }, []);

    const fetchIncidents = useCallback(() => {
        fetch(`${API_BASE}/incidents`)
            .then((r) => {
                if (!r.ok) throw new Error(`HTTP ${r.status}`);
                return r.json();
            })
            .then((data) => {
                const list = Array.isArray(data) ? data : (data.incidents || []);
                // Sort: open first, then by created date desc
                list.sort((a, b) => {
                    const ao = a.status === 'open' ? 0 : 1;
                    const bo = b.status === 'open' ? 0 : 1;
                    if (ao !== bo) return ao - bo;
                    return new Date(b.created_at || 0) - new Date(a.created_at || 0);
                });
                setIncidents(list);
                setLoading(false);
                setError(null);
            })
            .catch((err) => {
                setError(err.message);
                setLoading(false);
            });
    }, []);

    useEffect(() => {
        fetchIncidents();
        timerRef.current = setInterval(fetchIncidents, 15000);
        return () => clearInterval(timerRef.current);
    }, [fetchIncidents]);

    const toggleIncident = useCallback(
        (id) => {
            if (expandedId === id) {
                setExpandedId(null);
                return;
            }
            setExpandedId(id);
            if (timelineData[id]) return; // already loaded
            setTimelineLoading((prev) => ({ ...prev, [id]: true }));
            fetch(`${API_BASE}/incidents/${id}/timeline`)
                .then((r) => {
                    if (!r.ok) throw new Error(`HTTP ${r.status}`);
                    return r.json();
                })
                .then((data) => {
                    const events = Array.isArray(data) ? data : (data.events || data.timeline || []);
                    setTimelineData((prev) => ({ ...prev, [id]: events }));
                    setTimelineLoading((prev) => ({ ...prev, [id]: false }));
                })
                .catch(() => {
                    setTimelineData((prev) => ({ ...prev, [id]: [] }));
                    setTimelineLoading((prev) => ({ ...prev, [id]: false }));
                });
        },
        [expandedId, timelineData]
    );

    return (
        <div
            style={{
                background: '#060c14',
                border: '1px solid #1a3a4a',
                borderRadius: 10,
                padding: 16,
                fontFamily: 'JetBrains Mono, monospace',
                color: '#d0e8ff',
                margin: '16px 0',
            }}
        >
            {/* Header */}
            <div
                style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    marginBottom: 12,
                }}
            >
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <span style={{ fontSize: '1.1rem' }}>🕐</span>
                    <span
                        style={{
                            fontWeight: 700,
                            fontSize: '1rem',
                            color: '#29b6f6',
                            letterSpacing: '0.1em',
                        }}
                    >
                        INCIDENT TIMELINE
                    </span>
                    <span
                        style={{
                            fontSize: '0.7rem',
                            background: '#0d2b3e',
                            border: '1px solid #1a3a4a',
                            borderRadius: 4,
                            padding: '2px 8px',
                            color: '#78c8e8',
                        }}
                    >
                        {incidents.length} incidents
                    </span>
                </div>
                <button
                    onClick={fetchIncidents}
                    style={{
                        background: 'transparent',
                        border: '1px solid #29b6f6',
                        borderRadius: 4,
                        color: '#29b6f6',
                        cursor: 'pointer',
                        fontSize: '0.72rem',
                        padding: '3px 10px',
                    }}
                >
                    ↺ Refresh
                </button>
            </div>

            {/* Incident list */}
            {loading && (
                <div style={{ textAlign: 'center', color: '#29b6f6', padding: 24 }}>
                    Loading incidents…
                </div>
            )}
            {error && (
                <div style={{ color: '#ff5252', fontSize: '0.8rem', padding: 12 }}>
                    ⚠ API error: {error}
                    <div style={{ color: '#607d8b', fontSize: '0.7rem', marginTop: 4 }}>
                        Ensure the backend is running at {API_BASE}
                    </div>
                </div>
            )}
            {!loading && !error && incidents.length === 0 && (
                <div style={{ textAlign: 'center', color: '#607d8b', padding: 24 }}>
                    No incidents on record.
                </div>
            )}

            <div style={{ maxHeight: 480, overflowY: 'auto', paddingRight: 4 }}>
                {!loading &&
                    incidents.map((inc) => {
                        const sev = (inc.severity || 'info').toLowerCase();
                        const stat = (inc.status || 'open').toLowerCase();
                        const isOpen = expandedId === inc.id;
                        const ts = inc.created_at
                            ? new Date(inc.created_at).toLocaleString()
                            : '—';
                        return (
                            <div
                                key={inc.id}
                                style={{
                                    marginBottom: 8,
                                    borderRadius: 7,
                                    border: `1px solid ${isOpen ? '#29b6f6' : '#1a3a4a'}`,
                                    overflow: 'hidden',
                                    transition: 'border-color 0.2s',
                                }}
                            >
                                {/* Incident row */}
                                <div
                                    onClick={() => toggleIncident(inc.id)}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: 10,
                                        padding: '9px 12px',
                                        cursor: 'pointer',
                                        background: isOpen
                                            ? 'rgba(41,182,246,0.07)'
                                            : 'rgba(255,255,255,0.02)',
                                        userSelect: 'none',
                                    }}
                                >
                                    <StatusDot status={stat} />
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div
                                            style={{
                                                fontWeight: 600,
                                                fontSize: '0.83rem',
                                                color: '#e8f4ff',
                                                whiteSpace: 'nowrap',
                                                overflow: 'hidden',
                                                textOverflow: 'ellipsis',
                                            }}
                                        >
                                            {inc.title || `Incident #${inc.id}`}
                                        </div>
                                        <div
                                            style={{
                                                fontSize: '0.68rem',
                                                color: '#546e7a',
                                                marginTop: 2,
                                            }}
                                        >
                                            {ts}
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', gap: 6, alignItems: 'center', flexShrink: 0 }}>
                                        <span
                                            style={{
                                                fontSize: '0.65rem',
                                                padding: '1px 6px',
                                                borderRadius: 3,
                                                background: `${SEVERITY_COLOR[sev]}22`,
                                                color: SEVERITY_COLOR[sev] || '#607d8b',
                                                border: `1px solid ${SEVERITY_COLOR[sev]}55`,
                                                fontWeight: 700,
                                                textTransform: 'uppercase',
                                            }}
                                        >
                                            {sev}
                                        </span>
                                        <span
                                            style={{
                                                fontSize: '0.65rem',
                                                padding: '1px 6px',
                                                borderRadius: 3,
                                                background: `${STATUS_COLOR[stat]}22`,
                                                color: STATUS_COLOR[stat] || '#9e9e9e',
                                                border: `1px solid ${STATUS_COLOR[stat]}55`,
                                                textTransform: 'uppercase',
                                            }}
                                        >
                                            {stat}
                                        </span>
                                        <span
                                            style={{
                                                color: '#29b6f6',
                                                fontSize: '0.8rem',
                                                transform: isOpen ? 'rotate(90deg)' : 'none',
                                                transition: 'transform 0.2s',
                                                display: 'inline-block',
                                            }}
                                        >
                                            ▶
                                        </span>
                                    </div>
                                </div>

                                {/* Expanded timeline */}
                                {isOpen && (
                                    <div
                                        style={{
                                            padding: '4px 16px 12px 16px',
                                            background: 'rgba(6,12,20,0.85)',
                                            borderTop: '1px solid #1a3a4a',
                                        }}
                                    >
                                        {inc.description && (
                                            <div
                                                style={{
                                                    fontSize: '0.76rem',
                                                    color: '#8ab4c7',
                                                    margin: '8px 0 4px 0',
                                                }}
                                            >
                                                {inc.description}
                                            </div>
                                        )}
                                        <Timeline
                                            events={timelineData[inc.id]}
                                            loading={!!timelineLoading[inc.id]}
                                        />
                                        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 8 }}>
                                            {stat !== 'investigating' && (
                                                <button
                                                    onClick={() => setIncidentStatus(inc.id, 'investigating')}
                                                    style={{
                                                        fontSize: '0.65rem',
                                                        padding: '2px 8px',
                                                        borderRadius: 4,
                                                        border: '1px solid #ffc10766',
                                                        background: 'transparent',
                                                        color: '#ffc107',
                                                        cursor: 'pointer',
                                                    }}
                                                >
                                                    Mark investigating
                                                </button>
                                            )}
                                            {stat !== 'contained' && (
                                                <button
                                                    onClick={() => setIncidentStatus(inc.id, 'contained')}
                                                    style={{
                                                        fontSize: '0.65rem',
                                                        padding: '2px 8px',
                                                        borderRadius: 4,
                                                        border: '1px solid #29b6f666',
                                                        background: 'transparent',
                                                        color: '#29b6f6',
                                                        cursor: 'pointer',
                                                    }}
                                                >
                                                    Mark contained
                                                </button>
                                            )}
                                            {stat !== 'resolved' && (
                                                <button
                                                    onClick={() => setIncidentStatus(inc.id, 'resolved')}
                                                    style={{
                                                        fontSize: '0.65rem',
                                                        padding: '2px 8px',
                                                        borderRadius: 4,
                                                        border: '1px solid #4caf5066',
                                                        background: 'transparent',
                                                        color: '#4caf50',
                                                        cursor: 'pointer',
                                                    }}
                                                >
                                                    Mark resolved
                                                </button>
                                            )}
                                            {stat !== 'closed' && (
                                                <button
                                                    onClick={() => setIncidentStatus(inc.id, 'closed')}
                                                    style={{
                                                        fontSize: '0.65rem',
                                                        padding: '2px 8px',
                                                        borderRadius: 4,
                                                        border: '1px solid #9e9e9e66',
                                                        background: 'transparent',
                                                        color: '#9e9e9e',
                                                        cursor: 'pointer',
                                                    }}
                                                >
                                                    Close incident
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
            </div>
        </div>
    );
}
